<script lang="ts">import type{SelectOption}from'@fex/components-core/select/types';import PlusIcon from'@fex/components-svelte/icon/plus';import InputRoot from'@fex/components-svelte/primitive/input';import InputControl from'@fex/components-svelte/primitive/input-control';import SelectRoot from'@fex/components-svelte/primitive/select';import SelectContent from'@fex/components-svelte/primitive/select-content';import SelectList from'@fex/components-svelte/primitive/select-list';import SelectTrigger from'@fex/components-svelte/primitive/select-trigger';import Button from'@fex/components-svelte/ui/button';import Demo from'./demo-section.svelte';let options=$state<SelectOption[]>([{value:'jack',label:'Jack'},{value:'lucy',label:'Lucy'}]),name=$state('');function add(){const label=name.trim();if(!label||options.some(item=>item.value===label.toLocaleLowerCase()))return;options=[...options,{value:label.toLocaleLowerCase(),label}];name=''}</script><Demo title="Custom popup rendering" description="Custom content extends the default menu."><SelectRoot {options}><SelectTrigger placeholder="自定义下拉面板"/><SelectContent><SelectList/><div role="presentation" class="flex items-center gap-2 border-t border-border p-2" onpointerdown={event=>event.stopPropagation()}><InputRoot value={name} onValueChange={value=>name=value} class="flex-1"><InputControl placeholder="请输入新选项"/></InputRoot><Button size="sm" variant="ghost" onclick={add}><PlusIcon class="size-4"/>添加</Button></div></SelectContent></SelectRoot></Demo>
